module RefModule (
    input clk,
    input reset,
    input signal_in,
    output reg edge_detected
);
    reg unused_signal_prev;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            edge_detected <= 0;
            unused_signal_prev <= 0;
        end else begin
            edge_detected <= (signal_in && !unused_signal_prev);
            unused_signal_prev <= signal_in;
        end
    end
endmodule
